#include <bits/stdc++.h>
using namespace std;

int main() {
    string s, t;
    cin >> s >> t;

    int n = s.size();
    int m = t.size();

    int dp[n + 1][m + 1];

    for(int i = 0; i <= n; i++) {
        // Base cases
        dp[i][0] = 0;
        dp[0][i] = 0;
    }

    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= m; j++) {
            // Dp transitions
            dp[i][j] = max({dp[i - 1][j], dp[i][j - 1], (s[i - 1] == t[j - 1]) + dp[i - 1][j - 1]});
        }
    }

    cout << dp[n][m] << "\n";
    return 0;
}

